#include <iostream>
#include <string>

int main() {
  const int MAX_USERS = 100;
  const double PI = 3.14159;
  const std::string APP_NAME = "MyApp";
  std::cout << "Max Users: " << MAX_USERS << std::endl;
  std::cout << "Pi: " << PI << std::endl;
  std::cout << "App Name: " << APP_NAME << std::endl;
  return 0;
}
// Output:
// Max Users: 100
// Pi: 3.14159
// App Name: MyApp

#include <iostream>

int main() {
  constexpr int SQUARE_SIZE = 5 * 5;
  std::cout << "Square Size: " << SQUARE_SIZE << std::endl;
  return 0;
}
// Output:
// Square Size: 25

#include <iostream>

#define PI 3.14159

int main() {
  double radius = 5.0;
  double area = PI * radius * radius;
  std::cout << "Circle Area: " << area << std::endl;
  return 0;
}
// Output:
// Circle Area: 78.53975

#include <iostream>

const int GLOBAL_LIMIT = 500;

int main() {
  const int LOCAL_LIMIT = 100;
  std::cout << "Global Limit: " << GLOBAL_LIMIT << std::endl;
  std::cout << "Local Limit: " << LOCAL_LIMIT << std::endl;
  return 0;
}
// Output:
// Global Limit: 500
// Local Limit: 100

