  const double TAX_RATE = 0.2;
  const int MAX_ITEMS = 50;
  double price = 200.0;
  double total = price * (1 + TAX_RATE);
  std::cout << "Max Items: " << MAX_ITEMS << std::endl;
  std::cout << "Total Price: " << total << std::endl;
  return 0;
}
// Output:
// Max Items: 50
// Total Price: 240

